entry.content:
​​​plopjs​​​ 是一个基于node js开发的小工具，主要作用是根据模板代码生成目标代码。
什么是plpo它是一个命令行工具，专门用于构建生成器，这些生成器可以帮助开发者快速生成代码模板，特别是对于大型的后台管理系统，页面很多相似的内容，重复率很高的项目，我们可以设立一个模板（列表、详情、路由等）（vue、js、css文件等），一次构建重复创建。
用到的文档链接HandlebarsPlop插件plop
安装1.将plop添加到您的项目npm install plop -D

2.创建入口文件// plop 的入口文件 plopfile.js    // 需要导出一个函数，函数接收一个plop对象，用于创建生成器任务	import &#123; promises as fs &#125; from &#x27;node:fs&#x27;		export default async function (plop) &#123; //导出一个默认函数-异步  	plop.setWelcomeMessage(&#x27;请选择需要创建的模式：&#x27;) // 设置欢迎消息  	const items = await fs.readdir(&#x27;./plop-templates&#x27;)  // 获取plop-templates文件夹下的所有文件  	for (const item of items) &#123;    	const stat = await fs.lstat(`./plop-templates/$&#123;item&#125;`) //使用 fs.lstat 方法获取 plop-templates 文件夹中每个元素的状态（文件或目录），并将结果存储在 stat 变量中。    	if (stat.isDirectory()) &#123; //判断 stat 对象是否表示一个目录。如果是目录，则执行后续代码。     	 const prompt = await import(`./plop-templates/$&#123;item&#125;/prompt.js`) //    	  plop.setGenerator(item, prompt.default)  //循环设置生成器   	 &#125; 	 &#125;	&#125;


plop-templates文件夹下的文件夹必须得有prompt.js,要不然执行会报错，上面判断了只有文件夹才会设置生成器别的文件不会设置
3.添加命令在package.json中添加命令

注意，这里添加完，记得看一下package.json的type是不是module。因为我采用的是es的module模块，并不是 CommonJS。 	//package.json中添加&quot;type&quot;: &quot;module&quot;

添加模板1.在根目录下创建 plop-templates 文件夹
2.在plop-templates文件夹下创建所需要的模板
这里创建了3种模板
3.hbs模板 在对应的文件夹下创建hbs模板（Handlebars模板语法）

&#123;&#123;#if isFilesystem&#125;&#125;&lt;route lang=&quot;yaml&quot;&gt;meta:  title: 页面标题&lt;/route&gt;&#123;&#123;/if&#125;&#125;&lt;script setup lang=&quot;ts&quot;&gt;defineOptions(&#123;  name: &#x27;&#123;&#123; properCase componentName &#125;&#125;&#x27;,&#125;)&lt;/script&gt;&lt;template&gt;  &lt;div&gt;    &lt;!-- 布局 --&gt;  &lt;/div&gt;&lt;/template&gt;&lt;style scoped&gt;/* 样式 */&lt;/style&gt;

4.创建对应的生成器文件import fs from &#x27;node:fs&#x27;import path from &#x27;node:path&#x27;function getFolder(path) &#123;  const components = []  const files = fs.readdirSync(path)  files.forEach((item) =&gt; &#123;    console.log(&#x27;item&#x27;,item)    const stat = fs.lstatSync(`$&#123;path&#125;/$&#123;item&#125;`)    if (stat.isDirectory() === true &amp;&amp; item !== &#x27;components&#x27;) &#123;      components.push(`$&#123;path&#125;/$&#123;item&#125;`)      components.push(...getFolder(`$&#123;path&#125;/$&#123;item&#125;`))    &#125;  &#125;)  return components&#125;export default &#123;  description: &#x27;创建页面&#x27;,  prompts: [    &#123;      type: &#x27;list&#x27;,      name: &#x27;path&#x27;,      message: &#x27;请选择页面创建目录&#x27;,      choices: getFolder(&#x27;src/views&#x27;),    &#125;,    &#123;      type: &#x27;input&#x27;,      name: &#x27;name&#x27;,      message: &#x27;请输入文件名&#x27;,      validate: (v) =&gt; &#123;        if (!v || v.trim === &#x27;&#x27;) &#123;          return &#x27;文件名不能为空&#x27;        &#125;        else &#123;          return true        &#125;      &#125;,    &#125;,    &#123;      type: &#x27;confirm&#x27;,      name: &#x27;isFilesystem&#x27;,      message: &#x27;是否为基于文件系统的路由页面&#x27;,      default: false,    &#125;,    &#123;      type: &#x27;confirm&#x27;, // 问题的类型      name: &#x27;hasDetail&#x27;, // 问题对应得到答案的变量名，可以在actions中使用该变量      message: &#x27;是否需要详情抽屉：&#x27;, // 在命令行中的问题      default: true // 问题的默认答案    &#125;,  ],  actions: (data) =&gt; &#123;    const relativePath = path.relative(&#x27;src/views&#x27;, data.path)    const actions = [      &#123;        type: &#x27;add&#x27;, // 操作类型，这里是添加文件        path: `$&#123;data.path&#125;/&#123;&#123;dotCase name&#125;&#125;.vue`,// 模板生成的路径        templateFile: &#x27;plop-templates/page/index.hbs&#x27;,        data: &#123;          componentName: `$&#123;relativePath&#125; $&#123;data.name&#125;`,        &#125;,      &#125;,    ]    if (data.hasDetail) &#123;      actions.push(&#123;        type: &#x27;add&#x27;,        path: `$&#123;data.path&#125;/detail.vue`, // 模板生成的路径        templateFile: &#x27;plop-templates/page/detail.hbs&#x27;, // 模板的路径        data: &#123;          componentName: `$&#123;relativePath&#125; $&#123;data.name&#125;`,        &#125;,      &#125;)    &#125;    return actions  &#125;,&#125;

前期准备工作已经基本完成现在可以在控制台执行命令了
import fs from &#x27;node:fs&#x27;;import path from &#x27;node:path&#x27;;function getFolder(path) &#123;  const components = [];  const files = fs.readdirSync(path);  files.forEach((item) =&gt; &#123;    const stat = fs.lstatSync(`$&#123;path&#125;/$&#123;item&#125;`);    if (stat.isDirectory() === true &amp;&amp; item !== &#x27;components&#x27;) &#123;      components.push(`$&#123;path&#125;/$&#123;item&#125;`);      components.push(...getFolder(`$&#123;path&#125;/$&#123;item&#125;`));    &#125;  &#125;);  return components;&#125;export default &#123;  description: &#x27;创建页面&#x27;,  prompts: [    &#123;      type: &#x27;list&#x27;,      name: &#x27;path&#x27;,      message: &#x27;请选择页面创建目录&#x27;,      choices: getFolder(&#x27;src/views&#x27;),    &#125;,    &#123;      type: &#x27;input&#x27;,      name: &#x27;name&#x27;,      message: &#x27;请输入文件名&#x27;,      validate: (v) =&gt; &#123;        if (!v || v.trim() === &#x27;&#x27;) &#123;          return &#x27;文件名不能为空&#x27;;        &#125; else &#123;          return true;        &#125;      &#125;,    &#125;,    &#123;      type: &#x27;confirm&#x27;,      name: &#x27;isFilesystem&#x27;,      message: &#x27;是否为基于文件系统的路由页面&#x27;,      default: false,    &#125;,    &#123;      type: &#x27;confirm&#x27;,      name: &#x27;hasDetail&#x27;,      message: &#x27;是否需要详情抽屉：&#x27;,      default: true,    &#125;,  ],  actions: (data) =&gt; &#123;    const relativePath = path.relative(&#x27;src/views&#x27;, data.path);    const actions = [      &#123;        type: &#x27;add&#x27;,        path: `$&#123;data.path&#125;/&#123;&#123;dotCase name&#125;&#125;.vue`,        templateFile: &#x27;plop-templates/page/index.hbs&#x27;,        data: &#123;          componentName: `$&#123;relativePath&#125; $&#123;data.name&#125;`,        &#125;,      &#125;,    ];    if (data.hasDetail) &#123;      actions.push(&#123;        type: &#x27;add&#x27;,        path: `$&#123;data.path&#125;/detail.vue`,        templateFile: &#x27;plop-templates/page/detail.hbs&#x27;,        data: &#123;          componentName: `$&#123;relativePath&#125; $&#123;data.name&#125;`,        &#125;,      &#125;);    &#125;    // 添加 modify 操作    actions.push(&#123;      type: &#x27;modify&#x27;,      path: &#x27;src/router/index.js&#x27;,      pattern: /const routes = \[/,      template: `const routes = [\n  $1  &#123;\n    path: &#x27;/$&#123;data.name&#125;&#x27;,\n    name: &#x27;$&#123;data.name&#125;&#x27;,\n    component: () =&gt; import(&#x27;../views/$&#123;relativePath&#125;/$&#123;data.name&#125;.vue&#x27;),\n  &#125;,`,    &#125;);    return actions;  &#125;,&#125;;
